//! Co-retrieval ablation — the last unclosed loop from the "last look" swarm.
//! See docs/internal/PHASE0_RESULTS.md / LAST_LOOK.md.
//!
//! QUESTION: does Spectral's co-retrieval reranking (cross-query co-access
//! memory — a signal pgvector/MinHash+BM25 structurally lack) actually MOVE
//! rankings on the real brain, or is it inert like the spectrogram (0/500)?
//!
//! HONEST SCOPE: this measures whether the lever FIRES and how much it reorders
//! — NOT whether the reordering is *better*. It cannot: the co-access pairs are
//! generated by Spectral's own cascade, so any relevance label mined from them
//! is circular, and this brain has no independent label. So the only legitimate,
//! label-free readout is movement:
//!   - inert (≈0% of rankings change)      -> dead, clean negative, joins the list.
//!   - fires (meaningful % change)          -> real capability, but quality
//!                                             unmeasurable without a label this
//!                                             data doesn't have.
//!
//! Isolation: episode-diversity + context-dedup OFF so both arms hold identical
//! membership; the ONLY difference between arms is co_retrieval_weight
//! (0.10 vs an empty boost map). The result is a pure permutation diff.
//!
//! Usage: coret_ablation --brain ~/.permagent/brain --queries 300 --pool 40

use anyhow::{bail, Context, Result};
use rusqlite::Connection;
use std::collections::HashMap;
use std::path::PathBuf;

use spectral_graph::brain::{Brain, BrainConfig, EntityPolicy};
use spectral_graph::ranking::{
    apply_reranking_pipeline, compute_co_retrieval_boosts, RerankingConfig,
};
use spectral_graph::RecognitionContext;
use spectral_ingest::MemoryHit;

fn tokens(s: &str) -> Vec<String> {
    s.split(|c: char| !c.is_alphanumeric())
        .filter(|t| t.len() >= 3)
        .map(|t| t.to_lowercase())
        .collect()
}

/// Rank displacement between two permutations of the same id set.
struct Diff {
    top10_order_changed: bool,
    top5_set_changed: bool,
    mean_abs_rank_delta: f64,
    max_rank_delta: usize,
}

fn diff_rankings(off: &[MemoryHit], on: &[MemoryHit]) -> Diff {
    let pos_on: HashMap<&str, usize> = on.iter().enumerate().map(|(i, h)| (h.id.as_str(), i)).collect();
    let mut sum = 0usize;
    let mut maxd = 0usize;
    let mut counted = 0usize;
    for (i, h) in off.iter().enumerate() {
        if let Some(&j) = pos_on.get(h.id.as_str()) {
            let d = i.abs_diff(j);
            sum += d;
            maxd = maxd.max(d);
            counted += 1;
        }
    }
    let k = 10.min(off.len());
    let top10_order_changed = (0..k).any(|i| off.get(i).map(|h| &h.id) != on.get(i).map(|h| &h.id));
    let k5 = 5.min(off.len());
    let set_off: std::collections::HashSet<&str> = off[..k5].iter().map(|h| h.id.as_str()).collect();
    let set_on: std::collections::HashSet<&str> = on[..k5.min(on.len())].iter().map(|h| h.id.as_str()).collect();
    Diff {
        top10_order_changed,
        top5_set_changed: set_off != set_on,
        mean_abs_rank_delta: if counted > 0 { sum as f64 / counted as f64 } else { 0.0 },
        max_rank_delta: maxd,
    }
}

#[derive(clap::Parser)]
#[command(about = "Co-retrieval ablation on the real brain (label-free movement test)")]
struct Cli {
    /// Brain data dir (must contain ontology.toml + memory.db).
    #[arg(long, default_value = "~/.permagent/brain")]
    brain: String,
    #[arg(long, default_value_t = 300)]
    queries: usize,
    /// FTS candidate pool per query (real events returned ~40).
    #[arg(long, default_value_t = 40)]
    pool: usize,
    /// Anchor count for co-retrieval boost (top-N candidates as anchors).
    #[arg(long, default_value_t = 5)]
    anchors: usize,
    #[arg(long)]
    out: Option<String>,
}

fn expand(p: &str) -> String {
    if let Some(r) = p.strip_prefix("~/") {
        if let Ok(h) = std::env::var("HOME") {
            return format!("{h}/{r}");
        }
    }
    p.to_string()
}

fn main() -> Result<()> {
    let cli = <Cli as clap::Parser>::parse();
    let src_dir = PathBuf::from(expand(&cli.brain));
    let src_db = src_dir.join("memory.db");
    let src_ont = src_dir.join("ontology.toml");
    if !src_db.exists() {
        bail!("no memory.db in {src_dir:?}");
    }

    // Consistent snapshot into a fresh temp brain dir (never mutate production).
    let tmp = std::env::temp_dir().join(format!("coret_{}", std::process::id()));
    std::fs::create_dir_all(&tmp)?;
    let tmp_db = tmp.join("memory.db");
    let status = std::process::Command::new("sqlite3")
        .arg(&src_db)
        .arg(format!(".backup '{}'", tmp_db.display()))
        .status()
        .context("sqlite3 .backup")?;
    anyhow::ensure!(status.success(), "sqlite3 .backup failed");
    if src_ont.exists() {
        std::fs::copy(&src_ont, tmp.join("ontology.toml"))?;
    } else {
        std::fs::write(tmp.join("ontology.toml"), "")?;
    }

    let brain = Brain::open(BrainConfig {
        data_dir: tmp.clone(),
        ontology_path: tmp.join("ontology.toml"),
        memory_db_path: None,
        llm_client: None,
        wing_rules: None,
        hall_rules: None,
        entity_policy: EntityPolicy::Strict,
        sqlite_mmap_size: None,
        activity_wing: "activity".into(),
        redaction_policy: None,
        tact_config: None,
        device_id: None,
        enable_spectrogram: false,
    })
    .context("open brain")?;

    let pairs = brain.rebuild_co_retrieval_index().context("rebuild coret")?;
    eprintln!("co_retrieval_pairs rebuilt from retrieval_events: {pairs}");

    // Eval queries: derived from memories that appear in the co-access graph
    // (so candidates can intersect the boost surface — the fairest shot).
    let conn = Connection::open(&tmp_db)?;
    let mut stmt = conn.prepare(
        "SELECT DISTINCT m.content FROM memories m
         WHERE m.id IN (
            SELECT memory_id_a FROM co_retrieval_pairs
            UNION SELECT memory_id_b FROM co_retrieval_pairs)
         AND length(m.content) > 30
         ORDER BY m.id LIMIT ?1",
    )?;
    let contents: Vec<String> = stmt
        .query_map([cli.queries as i64], |r| r.get::<_, String>(0))?
        .filter_map(|r| r.ok())
        .collect();
    drop(stmt);
    eprintln!("built {} candidate queries", contents.len());

    let ctx = RecognitionContext::empty();
    let mut cfg = RerankingConfig::default();
    cfg.apply_ambient_boost = false;
    cfg.apply_context_dedup = false;   // isolate: identical membership both arms
    cfg.apply_episode_diversity = false;
    cfg.co_retrieval_weight = 0.10;
    let empty: HashMap<String, f64> = HashMap::new();

    let (mut evaluated, mut with_surface) = (0usize, 0usize);
    let (mut order_changed, mut set_changed) = (0usize, 0usize);
    let (mut sum_mean_delta, mut sum_boosted, mut max_delta_any) = (0.0f64, 0usize, 0usize);

    for content in &contents {
        let words: Vec<String> = tokens(content).into_iter().take(6).collect();
        if words.is_empty() {
            continue;
        }
        let cands = match brain.fts_search_direct(&words, cli.pool) {
            Ok(c) if c.len() >= 2 => c,
            _ => continue,
        };
        evaluated += 1;

        let boosts = compute_co_retrieval_boosts(&brain, &cands, cli.anchors);
        let boosted_here = cands.iter().filter(|h| boosts.get(&h.id).is_some_and(|&v| v > 0.0)).count();
        if !boosts.is_empty() && boosted_here > 0 {
            with_surface += 1;
        }
        sum_boosted += boosted_here;

        let off = apply_reranking_pipeline(cands.clone(), &cfg, &ctx, &empty);
        let on = apply_reranking_pipeline(cands.clone(), &cfg, &ctx, &boosts);
        let d = diff_rankings(&off, &on);
        if d.top10_order_changed {
            order_changed += 1;
        }
        if d.top5_set_changed {
            set_changed += 1;
        }
        sum_mean_delta += d.mean_abs_rank_delta;
        max_delta_any = max_delta_any.max(d.max_rank_delta);
    }

    let n = evaluated.max(1) as f64;
    let report = serde_json::json!({
        "pairs_index": pairs,
        "pool": cli.pool,
        "anchors": cli.anchors,
        "co_retrieval_weight": 0.10,
        "queries_evaluated": evaluated,
        "queries_with_boost_surface": with_surface,
        "frac_with_surface": with_surface as f64 / n,
        "frac_top10_order_changed": order_changed as f64 / n,
        "frac_top5_set_changed": set_changed as f64 / n,
        "mean_boosted_candidates_per_pool": sum_boosted as f64 / n,
        "mean_abs_rank_delta": sum_mean_delta / n,
        "max_rank_delta_any_query": max_delta_any,
        "note": "movement only; NOT quality. co-access pairs are cascade-generated -> any relevance label mined from them is circular. This brain has no independent label.",
    });
    let out = serde_json::to_string_pretty(&report)?;
    println!("{out}");
    if let Some(p) = &cli.out {
        std::fs::write(p, &out)?;
        eprintln!("wrote {p}");
    }

    let _ = std::fs::remove_dir_all(&tmp);

    eprintln!("\n── Co-retrieval ablation ────────────────────────");
    eprintln!("pairs index:        {pairs}");
    eprintln!("queries evaluated:  {evaluated}");
    eprintln!(
        "had boost surface:  {:.1}%  ({} queries)",
        100.0 * with_surface as f64 / n,
        with_surface
    );
    eprintln!("top-5 set changed:  {:.1}%", 100.0 * set_changed as f64 / n);
    eprintln!("top-10 order chg:   {:.1}%", 100.0 * order_changed as f64 / n);
    eprintln!("mean |Δrank|:       {:.2}  (max {max_delta_any})", sum_mean_delta / n);
    let verdict = if set_changed as f64 / n < 0.02 {
        "INERT — co-retrieval effectively does not move rankings; joins the dead list."
    } else {
        "FIRES — moves rankings, but quality unmeasurable (circular label). Real but unproven."
    };
    eprintln!("VERDICT: {verdict}");
    Ok(())
}
